INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Perito en Desarrollo Comunitario - Sexto Año', 'Desarrollo Comunitario', '1. Promueve la organización comunitaria, enfocada hacia la toma de decisiones y solución de problemas, con el propósito de lograr el desarrollo de su comunidad.', ARRAY['1.1. Emplea términos relacionados con el desarrollo comunitario.', '1.2. Identifica las necesidades e intereses de la comunidad por medio del diagnóstico comunitario.', '1.3. Propone soluciones a problemas a partir de estrategias establecidas.']),
('Perito en Desarrollo Comunitario - Sexto Año', 'Desarrollo Comunitario', '2. Propicia la participación comunitaria en el proceso de mejoramiento sostenido y equitativo de la calidad de vida de los habitantes, basado en medidas de conservación y protección del medio ambiente.', ARRAY['2.1. Aplica técnicas innovadoras que se orientan hacia el desarrollo de la comunidad.', '2.2. Participa en el proceso de mejoramiento comunitario.', '2.3. Realiza acciones de sostenibilidad y sustentabilidad comunitaria, sin perder de vista la protección ambiental.']);
